module async_to_sync_reset_shift(
	input clk,
	input Pinput,
	output Poutput
);
parameter LENGTH =8;
parameter INPUT_POLARITY = 1'b1;
parameter OUTPUT_POLARITY= 1'b1;

reg [LENGTH-1:0] shift=0;
always @(Pinput or (clk)) begin
	if ( Pinput == INPUT_POLARITY ) begin
		shift <= {LENGTH{OUTPUT_POLARITY}};
	end
	else if (clk) begin
		shift <= {shift[LENGTH-2:0], ~OUTPUT_POLARITY};
	end
end
// Output the result on edge - helps to meet timing
//always @(posedge clk) begin
//  Poutput <= shift[LENGTH-1];
//end
assign Poutput=shift[LENGTH-1];
endmodule

`timescale 1ns / 1ns

// I'm not going to write a test bench for this module,
// but rather assume that if this breaks,
// all the modules that use it will also break.
module reg_tech_cdc(
    input I,
    input C,
    output O
);
parameter POST_STAGES=1;

// Probably OK to stack up various vendor-specific attributes here.
// If incompatibilities are discovered, maybe they can be addressed
// with preprocessor magic.
// Worst-case, you can make a pin-compatible module that
// does black-block instantiation.
(* ASYNC_REG = "TRUE" *) (* magic_cdc *) reg r1=0;
(* ASYNC_REG = "TRUE" *) reg r2=0;
always @(posedge C) begin
    r1 <= I;
    r2 <= r1;
end
assign O = (POST_STAGES==0) ? r1 : r2;

endmodule

